const data = $input.first().json;
const temp = data.current?.temperature_2m || 15;
const apparent = data.current?.apparent_temperature || temp;
const humidity = data.current?.relative_humidity_2m || 50;
const forecastMaxTemps = data.daily?.temperature_2m_max || [];
const forecastApparent = data.daily?.apparent_temperature_max || [];

// UK Met Office heatwave thresholds
// Heatwave: 3+ consecutive days >= 25°C (Scotland: 28°C threshold for alert)
const highTempDays = forecastMaxTemps.filter(t => t >= 25).length;
const veryHighDays = forecastMaxTemps.filter(t => t >= 28).length;
const maxForecastTemp = Math.max(...forecastMaxTemps.map(t => t || 0));
const maxApparent = Math.max(...forecastApparent.map(t => t || 0));

// Heat index calculation
const heatIndex = apparent > 27 ? apparent + (humidity - 40) * 0.1 : apparent;

let severity = 'Low';
let probability = 0.05;
let action = 'monitor';
let healthRisk = 'minimal';

if (veryHighDays >= 3 || maxApparent >= 35) {
  severity = 'Critical'; probability = 0.85; action = 'issue_critical_heat_alert'; healthRisk = 'extreme';
} else if (highTempDays >= 3 || maxApparent >= 30) {
  severity = 'High'; probability = 0.65; action = 'issue_heat_warning'; healthRisk = 'high';
} else if (highTempDays >= 1 || maxForecastTemp >= 25) {
  severity = 'Medium'; probability = 0.40; action = 'issue_heat_advisory'; healthRisk = 'moderate';
}

return [{ json: {
  incidentType: 'heatwave',
  severity,
  probability,
  currentTemp: temp,
  apparentTemp: apparent,
  humidity,
  heatIndex: Math.round(heatIndex * 10) / 10,
  forecastMaxTemp: maxForecastTemp,
  highTempDays,
  veryHighDays,
  healthRisk,
  action,
  shouldAlert: severity !== 'Low',
  vulnerableGroupsAtRisk: severity === 'Critical' || severity === 'High',
  timestamp: new Date().toISOString()
}}];
